def compute_score() -> tuple[str, float]:
    # Find Slide 5 in the modified deck
    slide_number = 5
    # Find the corresponding slide_id for slide 5
    # Use VLM to visually inspect before/after slide 5
    orig_img = None
    mod_img = None
    for s in original_ppt_screenshots:
        if s.slide_number == slide_number:
            orig_img = s.image_path
            break
    for s in modified_ppt_screenshots:
        if s.slide_number == slide_number:
            mod_img = s.image_path
            break
    if not (orig_img and mod_img):
        return ("Slide 5 screenshots missing for before or after.", 0.0)
    prompt = (
        "You are given two images: the before and after screenshots of slide 5 in a PowerPoint presentation.\n"
        "The original slide contains a red annotation on a chart. This annotation consists of text that reads '43 year horizon' and an arrow pointing to the chart.\n"
        "Has the text '43 year horizon' been removed? Answer with 'text:yes' or 'text:no'.\n"
        "Has the arrow been removed? Answer with 'arrow:yes' or 'arrow:no'.\n"
        "Provide the answers on separate lines."
    )
    response = vlm_call(prompt, images=[orig_img, mod_img], temperature=0.0, max_tokens=20)
    response_lower = response.lower()
    text_removed = 'text:yes' in response_lower
    arrow_removed = 'arrow:yes' in response_lower

    score = 0.0
    if text_removed:
        score += 0.5
    if arrow_removed:
        score += 0.5

    if score == 1.0:
        return ("Annotation '43 year horizon' and arrow successfully removed from slide 5 chart.", 1.0)
    elif score == 0.5:
        if text_removed:
            return ("Annotation text '43 year horizon' removed, but arrow remains.", 0.5)
        else: # arrow_removed
            return ("Annotation arrow removed, but text '43 year horizon' remains.", 0.5)
    else:
        return ("Neither annotation text nor arrow were removed. VLM response: " + response.strip(), 0.0)

def compute_score() -> tuple[str, float]:
    # If there are no modifications except for annotation removal, that's fine
    # We'll use the screenshots to check for extraneous changes
    orig_img = None
    mod_img = None
    slide_number = 5
    for s in original_ppt_screenshots:
        if s.slide_number == slide_number:
            orig_img = s.image_path
            break
    for s in modified_ppt_screenshots:
        if s.slide_number == slide_number:
            mod_img = s.image_path
            break
    if not (orig_img and mod_img):
        return ("Slide 5 screenshots missing for before or after.", 0.0)
    vlm_prompt = (
        "You are given two images: the before and after screenshots of slide 5 in a PowerPoint presentation.\n"
        "Aside from the possible removal of the red annotation '43 year horizon' from the chart, has ANY other part of the slide changed, newly added, or removed between the before and after?\n"
        "This includes text, layout, colors, images, or other chart elements.\n"
        "Only respond in YES or NO."
    )
    response = vlm_call(vlm_prompt, images=[orig_img, mod_img], temperature=0.0, max_tokens=5)
    if 'no' in response.lower():
        return (response+", No extraneous changes to slide 5 aside from annotation removal.", 1.0)
    return (response+", Extraneous changes detected on slide 5: " + response.strip(), 0.0)

def compute_score() -> tuple[str, float]:
    # Check for any changes outside of slide 5
    changed_slide_numbers = set()
    for sl in ppt_diff.added_slides + ppt_diff.removed_slides:
        changed_slide_numbers.add(sl.slide_number)
    for s0, s1 in ppt_diff.modified_slides:
        changed_slide_numbers.add(s0.slide_number)
        changed_slide_numbers.add(s1.slide_number)
    changed_slide_numbers.discard(5)
    if changed_slide_numbers:
        return (f"Slides other than 5 were modified: {sorted(list(changed_slide_numbers))}", 0.0)
    # Also check for animations or transitions on other slides
    for anim in ppt_diff.added_animations + ppt_diff.removed_animations:
        # Find slide_number
        for s in ppt_diff.added_slides + ppt_diff.removed_slides + [s[1] for s in ppt_diff.modified_slides]:
            if hasattr(s, 'slide_id') and s.slide_id == anim.slide_id:
                if s.slide_number != 5:
                    return (f"Animations were modified on slide {s.slide_number}.", 0.0)
    for tr in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        for s in ppt_diff.added_slides + ppt_diff.removed_slides + [s[1] for s in ppt_diff.modified_slides]:
            if hasattr(s, 'slide_id') and s.slide_id == tr.slide_id:
                if s.slide_number != 5:
                    return (f"Transitions were modified on slide {s.slide_number}.", 0.0)
    return ("No unintended changes to slides other than 5.", 1.0)
